import React, { useState } from "react";

const CustomerManager = () => {
  const [customers, setCustomers] = useState([
    { id: 1, name: "john doe" },
    { id: 2, name: "sarah smith" },
    { id: 3, name: "michael jordan" },
    { id: 4, name: "emily davis" },
  ]);
  
  const [searchTerm, setSearchTerm] = useState("");

  // Helper to format names: "john doe" -> "John Doe"
  const formatName = (str) => {
    return str
      .toLowerCase()
      .split(" ")
      .map((word) => word.charAt(0).toUpperCase() + word.slice(1))
      .join(" ");
  };

  const deleteCustomer = (id) => {
    setCustomers(customers.filter((c) => c.id !== id));
  };

  const watchCustomer = (customer) => {
    alert(`Customer Details:\nName: ${formatName(customer.name)}\nID: ${customer.id}`);
  };

  // Filter logic
  const filteredCustomers = customers.filter((customer) =>
    customer.name.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="min-h-screen bg-gray-900 p-8 flex justify-center font-sans">
      <div className="w-full max-w-md bg-[#1a1c23] p-6 rounded-lg shadow-xl border border-gray-800">
        <h2 className="text-[#d4af37] text-xl font-semibold mb-6 tracking-wide uppercase flex items-center gap-2">
          <span className="material-symbols-outlined">group</span>
          Customer Directory
        </h2>

        {/* Search Bar Section */}
        <div className="mb-8">
          <label className="block text-[#d4af37] text-sm font-bold mb-2 ml-1">
            Search Customers
          </label>
          <div className="relative">
            <span className="material-symbols-outlined absolute left-3 top-1/2 -translate-y-1/2 text-[#888da8] text-[20px]">
              search
            </span>
            <input
              type="text"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              placeholder="Type a name..."
              className="w-full bg-[#2d303e] text-[#e8e8e8] border border-[#4a4e69] pl-10 pr-4 py-2 rounded focus:border-[#d4af37] outline-none transition-all placeholder:text-[#888da8] placeholder:opacity-80"
            />
          </div>
        </div>

        {/* List Section */}
        <div className="space-y-3">
          <div className="flex justify-between items-center mb-2 px-1">
            <p className="text-[#888da8] text-xs uppercase tracking-widest font-bold">
              Results ({filteredCustomers.length})
            </p>
          </div>

          {filteredCustomers.map((customer) => (
            <div
              key={customer.id}
              className="flex items-center justify-between bg-[#252525] p-3 rounded border-l-4 border-[#d4af37] hover:bg-[#2d303e] transition-all group"
            >
              <span className="text-[#e8e8e8] font-medium tracking-tight">
                {formatName(customer.name)}
              </span>
              
              <div className="flex items-center gap-1">
                {/* View Icon */}
                <button
                  onClick={() => watchCustomer(customer)}
                  className="text-[#888da8] hover:text-[#d4af37] transition-colors p-2 flex items-center"
                  title="View details"
                >
                  <span className="material-symbols-outlined text-[20px]">visibility</span>
                </button>

                {/* Delete Icon */}
                <button
                  onClick={() => deleteCustomer(customer.id)}
                  className="text-[#888da8] hover:text-red-500 transition-colors p-2 flex items-center"
                  title="Delete record"
                >
                  <span className="material-symbols-outlined text-[20px]">delete</span>
                </button>
              </div>
            </div>
          ))}

          {filteredCustomers.length === 0 && (
            <div className="text-center py-10 border border-dashed border-[#4a4e69] rounded">
               <span className="material-symbols-outlined text-[#4a4e69] text-4xl block mb-2">
                person_search
              </span>
              <p className="text-[#4a4e69] italic">
                No matching customers found
              </p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default CustomerManager;